def me(t):
    r = requests.get(f"https://eodhd.com/api/eod/{t}",
        params={"api_token": EODHD_API_KEY, "fmt": "json", "from": "2010-12-01", "to": "2026-06-18"}, timeout=30)
    d = pd.DataFrame(r.json()); d["date"] = pd.to_datetime(d["date"])
    s = d.set_index("date")["close"].sort_index().resample("ME").last()
    s.index = s.index.to_period("M").astype(str); return s


def main():
    nb = pd.Series(NB)
    ndx = me("IXIC.INDX")
    df = pd.DataFrame({"nb": nb, "ndx": ndx}).dropna()
    df["ret"] = df["ndx"].pct_change() * 100
    df["nb12"] = df["nb"].rolling(12).sum()
    df["cum"] = df["nb"].cumsum()

    c0 = df["nb"].corr(df["ret"])
    cl = df["nb"].corr(df["ret"].shift(-1))
    cg = df["nb"].corr(df["ret"].shift(1))
    print(f"기간 {df.index[0]}~{df.index[-1]} ({len(df)}개월)")
    print(f"동월 corr(순매수,나스닥수익) {c0:+.2f} / 순매수→다음달 {cl:+.2f} / 전달수익→순매수(추격) {cg:+.2f}")
    print(f"누적 순매수 합계: ${df['cum'].iloc[-1]:,.0f}M  (~${df['cum'].iloc[-1]/1000:.1f}B)")
    yr = df.groupby(lambda x: x[:4])["nb"].sum()
    print("\n연도별 순매수합($M):")
    for y, v in yr.items(): print(f"  {y}: {v:+,.0f}")

    import matplotlib; matplotlib.use("Agg")
    import matplotlib.pyplot as plt
    matplotlib.rcParams["font.family"] = "Malgun Gothic"; matplotlib.rcParams["axes.unicode_minus"] = False
    x = list(range(len(df))); lab = list(df.index); st = max(1, len(x)//28)
    fig, ax = plt.subplots(3, 1, figsize=(16, 13))

    # 상단: 월별 순매수 + 나스닥(로그)
    ax[0].bar(x, df["nb"], color=["#d62728" if v >= 0 else "#1f77b4" for v in df["nb"]], width=.9)
    ax[0].axhline(0, color="k", lw=.6); ax[0].set_ylabel("월별 순매수 ($M)")
    a2 = ax[0].twinx(); a2.plot(x, df["ndx"], "k-", lw=1.4, label="나스닥"); a2.set_yscale("log"); a2.set_ylabel("나스닥(로그)"); a2.legend(loc="upper left")
    ax[0].set_xticks(x[::st]); ax[0].set_xticklabels(lab[::st], rotation=45, fontsize=7)
    ax[0].set_title(f"월별 순매수(막대) vs 나스닥(선)  ·  동월 {c0:+.2f} / 선행 {cl:+.2f} / 추격 {cg:+.2f}")

    # 중단: 12M 이동합
    ax[1].fill_between(x, df["nb12"], 0, color="#2ca02c", alpha=.4)
    ax[1].plot(x, df["nb12"], color="#2ca02c", lw=1.3, label="순매수 12M 이동합")
    ax[1].axhline(0, color="k", lw=.6); ax[1].set_ylabel("순매수 12M합 ($M)")
    a3 = ax[1].twinx(); a3.plot(x, df["ndx"], "k-", lw=1.2); a3.set_yscale("log"); a3.set_ylabel("나스닥(로그)")
    ax[1].set_xticks(x[::st]); ax[1].set_xticklabels(lab[::st], rotation=45, fontsize=7)
    ax[1].legend(loc="upper left"); ax[1].set_title("순매수 12개월 이동합(연간 매수 강도) vs 나스닥")

    # 하단: 누적
    ax[2].plot(x, df["cum"], color="#9467bd", lw=2, label="누적 순매수 ($M)")
    ax[2].set_ylabel("누적 순매수 ($M)"); ax[2].axhline(0, color="k", lw=.5)
    a4 = ax[2].twinx(); a4.plot(x, df["ndx"], "k-", lw=1.2, label="나스닥"); a4.set_yscale("log"); a4.set_ylabel("나스닥(로그)")
    ax[2].set_xticks(x[::st]); ax[2].set_xticklabels(lab[::st], rotation=45, fontsize=7)
    ax[2].legend(loc="upper left"); ax[2].set_title("누적 순매수 vs 나스닥")

    fig.suptitle("서학개미 월별 순매수(SEIBRO 전체) vs 나스닥 (2011~2026)", fontsize=15)
    fig.tight_layout(rect=[0, 0, 1, 0.975])
    out = HERE / "data" / "seibro_netbuy_nasdaq_2011.png"
    fig.savefig(out, dpi=130); print(f"\n저장: {out}")


if __name__ == "__main__":
    main()
